    def test_non_list_input(self):
        with pytest.raises(TypeError):
            rotate_list("not a list", 1)

        with pytest.raises(TypeError):
            rotate_list(123, 1)

        with pytest.raises(TypeError):
            rotate_list({'a': 1}, 1)

